```class Solution {
public:
    int minAddToMakeValid(string s) {
        int n = s.length();
        int moves = 0;
        for (int i = n - 1; i >= 0; i--) {
            if (s[i] == ')') {
                moves++;
                for (int j = i + 1; j < n; j++) {
                    if (s[j] != '(') {
                        moves++;
                        break;
                    }
                }
            }
        }
        return moves;
    }
};```

